import { useQuery } from '@tanstack/react-query';
import clsx from 'clsx';
import { AnimatePresence, motion } from 'framer-motion';
import { useState } from 'react';
import { FormattedMessage } from 'react-intl';

import Spacings from '@dynatrace/strato-design-tokens/spacings';
import { getAppName } from '@dynatrace-sdk/app-environment';
import { getSegmentsPresets } from '@dynatrace-sdk/segments-presets';

import { isSelectedPreset } from './isSelectedPreset.js';
import {
  expandAndCollapseAnimationVariants,
  SegmentsPreset,
} from './SegmentsPreset.js';
import * as styles from './SegmentsPresets.sty.js';
import { Divider } from '../../../../layouts/divider/Divider.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { Text } from '../../../../typography/text/Text.js';
import { segmentsClient } from '../../contexts/SegmentsCache/SegmentsCache.js';
import { useSegments } from '../../hooks/useSegments.js';
import * as animationHelperStyles from '../Overlay.sty.js';
import { ShowMorePanel } from '../ShowMorePanel/ShowMorePanel.js';

const PIN_LIMIT = 10;

export const SegmentsPresetList = ({
  showDivider,
}: {
  showDivider: boolean;
}) => {
  const { segments } = useSegments();
  const { data, isLoading } = useQuery(
    {
      queryKey: ['getSegmentsPresets'],
      queryFn: getSegmentsPresets,
      notifyOnChangeProps: ['dataUpdatedAt'],
    },
    segmentsClient.queryClient,
  );
  const [isAnimating, setIsAnimating] = useState(false);

  if (
    !data ||
    (data.pinnedPresets.length === 0 && data.recentPresets.length === 0) ||
    isLoading
  ) {
    return null;
  }
  const pinLimitReached = data.pinnedPresets.length >= PIN_LIMIT;

  const recentPresets = data.recentPresets?.map((preset) => (
    <li
      key={`recent-${preset.id}`}
      className={styles.listItem}
      data-dt-name="Recent"
    >
      <SegmentsPreset
        uiPreset={preset}
        id={preset.id}
        pinLimitReached={pinLimitReached}
        isPinned={data.pinnedPresets.some(
          (pinnedPreset) => preset.id === pinnedPreset.id,
        )}
        isSelected={isSelectedPreset(segments, preset.segments)}
      />
    </li>
  ));

  const primaryContent =
    recentPresets.length > 3 ? recentPresets.slice(0, 2) : recentPresets;
  const extendedContent =
    recentPresets.length > 3 ? recentPresets.slice(2) : null;

  const showRecent = data.recentPresets.length > 0;
  const showPinned = data.pinnedPresets.length > 0;

  return (
    <>
      {showDivider && <Divider />}
      <Flex
        flexDirection="column"
        width="100%"
        px={0}
        pb={4}
        gap={0}
        pt={showDivider ? 12 : 0}
        className={clsx({
          [animationHelperStyles.isAnimating]: isAnimating,
        })}
      >
        {showRecent && (
          <Flex flexDirection="column" gap={0} width="100%">
            <Text
              textStyle="small-emphasized"
              className={styles.sectionHeadline}
            >
              <FormattedMessage
                id="QZdQoUnAWKJYAyK2"
                defaultMessage="Recently used"
                description="Headline to group recently used segments presets."
              />
            </Text>

            {/** The AnimatePresence is needed here to prevent the initial animation of the recent presets. */}
            <AnimatePresence initial={false} key="recent-presets">
              <ShowMorePanel>
                <ShowMorePanel.PrimaryContent>
                  {primaryContent}
                </ShowMorePanel.PrimaryContent>
                {extendedContent && (
                  <ShowMorePanel.ExtendedContent>
                    {extendedContent}
                  </ShowMorePanel.ExtendedContent>
                )}
              </ShowMorePanel>
            </AnimatePresence>
          </Flex>
        )}
        <AnimatePresence initial={false} key="pinned-presets">
          {showPinned && (
            <Flex
              as={motion.div}
              flexDirection="column"
              gap={4}
              variants={expandAndCollapseAnimationVariants}
              initial="exit"
              animate="enter"
              exit="exit"
              onAnimationStart={() => setIsAnimating(true)}
              onAnimationComplete={() => setIsAnimating(false)}
            >
              {showRecent && showPinned && <Divider />}
              <Text
                key="pinned-header"
                textStyle="small-emphasized"
                className={styles.sectionHeadline}
                style={{ paddingTop: Spacings.Size12 }}
              >
                <FormattedMessage
                  key="pinned-header-text"
                  id="568KZGFcxrq95nEC"
                  defaultMessage="Pinned in {appName}"
                  description="Headline to group recently used segments presets."
                  values={{ appName: getAppName() }}
                />
              </Text>
              <ul className={styles.list}>
                <AnimatePresence initial={false} key="pinned-presets-list">
                  {data.pinnedPresets.map((preset) => (
                    <li
                      key={`pinned-${preset.id}`}
                      className={styles.listItem}
                      data-dt-name="Pinned"
                    >
                      <SegmentsPreset
                        uiPreset={preset}
                        id={preset.id}
                        pinLimitReached={pinLimitReached}
                        isPinned={true}
                        isSelected={isSelectedPreset(segments, preset.segments)}
                      />
                    </li>
                  ))}
                </AnimatePresence>
              </ul>
            </Flex>
          )}
        </AnimatePresence>
      </Flex>
    </>
  );
};
